import json
import re
from urllib.parse import urlparse


def _is_http_url(u: str) -> bool:
    try:
        p = urlparse(u)
    except Exception:
        return False
    return p.scheme in ("http", "https") and bool(p.netloc)


def _parse_top_urls(text: str) -> list[str]:
    t = (text or "").strip()
    if not t:
        raise ValueError("search_1: пустой ответ LLM")

    m = re.search(r"```(?:json)?\\s*(\\{[\\s\\S]*?\\})\\s*```", t, re.IGNORECASE | re.DOTALL)
    if m:
        blob = m.group(1).strip()
    else:
        i = t.find("{")
        if i == -1:
            raise ValueError("search_1: в ответе нет JSON-объекта")
        blob = t[i:].strip()

    dec = json.JSONDecoder()
    obj, _ = dec.raw_decode(blob)
    if not isinstance(obj, dict):
        raise ValueError("search_1: корень JSON должен быть объектом")

    top_urls = obj.get("top_urls")
    if not isinstance(top_urls, list):
        raise ValueError("search_1: поле top_urls должно быть списком")

    picked: list[str] = []
    for x in top_urls:
        u = str(x).strip()
        if not u:
            continue
        if not _is_http_url(u):
            continue
        picked.append(u)
        if len(picked) >= 3:
            break

    return picked


async def run(state):
    text = getattr(state, "response", None)
    if not isinstance(text, str):
        raise ValueError("search_1: ожидается state.response со строкой от LLM")

    state["search1_urls"] = _parse_top_urls(text)

    merged_vars = dict(getattr(state, "variables", None) or {})
    merged_vars["search1_urls"] = state["search1_urls"]
    state.variables = merged_vars
    return state

