from urllib.parse import urlparse

MAX_SLOTS = 9


def _is_http_url(u: str) -> bool:
    try:
        p = urlparse(u)
    except Exception:
        return False
    return p.scheme in ('http', 'https') and bool(p.netloc)


async def run(state):
    urls = []
    for k in ('search1_urls', 'search2_urls', 'search3_urls'):
        part = state.get(k)
        if not isinstance(part, list):
            continue
        for x in part:
            urls.append(str(x).strip())

    seen = set()
    picked = []
    for u in urls:
        if not u or not _is_http_url(u):
            continue
        if u in seen:
            continue
        seen.add(u)
        picked.append(u)
        if len(picked) >= MAX_SLOTS:
            break

    state['crawl_target_count'] = len(picked)
    state['crawl_target_urls'] = list(picked)
    for i in range(1, MAX_SLOTS + 1):
        if i <= len(picked):
            state[f'target_url_{i}'] = picked[i - 1]
        else:
            state[f'target_url_{i}'] = ''
    return state
